  records = ["192.0.2.3"] # Replace with the actual IP address of replica-2
}

resource "aws_route53_weighted_routing_policy" "weighted_routing" {
  zone_id = aws_route53_zone.main.zone_id

  weight_records {
    record = aws_route53_record.primary.name
    weight = 60 # 60% of traffic to the primary instance
  }

  weight_records {
    record = aws_route53_record.replica_1.name
    weight = 20 # 20% of traffic to replica-1
  }

  weight_records {
    record = aws_route53_record.replica_2.name
    weight = 20 # 20% of traffic to replica-2
  }
}

