  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "ec2.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF

  tags = {
    Name = "Elastic Beanstalk EC2 Role"
  }
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name               = "eb_ec2_profile"
  roles               = [aws_iam_role.eb_ec2_role.name]
  path               = "/"
  tags = {
    Name = "Elastic Beanstalk EC2 Instance Profile"
  }
}

resource "aws_elasticbeanstalk_application" "my_application" {
  name        = "my_application"
  description = "Elastic Beanstalk application created with Terraform"
}

