  application_name = aws_elasticbeanstalk_application.my_application.name
  environment_name = "environment-one"
  solution_stack_name = "64bit Amazon Linux 2 v3.5 running Python 3.9"  # Choose appropriate stack
  version_label = "v1"
  platform_environment {
    instance_type = "t2.micro" # Choose appropriate instance type
  }

  settings = [
    {
      namespace = "aws:autoscaling:launchconfiguration"
      option_name = "InstanceIamRole"
      option_value = aws_iam_role.eb_ec2_role.name
    },
    {
      namespace = "aws:elasticbeanstalk:environment"
      option_name = "EnvironmentType"
      option_value = "SingleInstance"
    }
  ]
}

