  name         = "version"
  application_name = aws_elasticbeanstalk_application.myapp.name
  source_bundle {
    s3_bucket = "examplebucket_object" # Replace with your S3 bucket
    s3_key    = "my_app_bundle.zip" # Replace with your source bundle key
  }
}

# Elastic Beanstalk Environment
resource "aws_elasticbeanstalk_environment" "eb_env" {
  name             = "eb-env"
  application_name = aws_elasticbeanstalk_application.myapp.name
  environment_type = "SingleInstance"
  solution_stack_name = "64bit Amazon Linux 2 v3.6.6 running Node.js 18" # Choose appropriate stack
  version_label    = aws_elasticbeanstalk_application_version.version.version
  settings {
    tier {
      name = "WebServer"
      type = "Standard"
    }
  }
}

# IAM Role for Elastic Beanstalk
resource "aws_iam_role" "eb_ec2_role" {
  name               = "eb_ec2_role"
  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "elasticbeanstalk.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

# Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}


# Route 53 Record to point to Elastic Beanstalk Environment
resource "aws_route53_record" "alias" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com" # Replace with your desired subdomain
  type    = "A"
  alias {
    name                   = aws_elasticbeanstalk_environment.eb_env.cname
    zone_id                = aws_elasticbeanstalk_environment.eb_env.region
    evaluate_target_health = true
  }
}

