provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Replace with your actual Elastic Beanstalk environment names and domain
variable "eb_blue_env_name" {
  type    = string
  default = "blue"
}

variable "eb_green_env_name" {
  type    = string
  default = "green"
}

variable "domain_name" {
  type    = string
  default = "example.com" # Replace with your domain name
}

variable "hosted_zone_id" {
  type    = string
  default = "Z1ABCDEFGHIJKLMN" # Replace with your Hosted Zone ID
}

data "aws_elasticbeanstalk_environment" "blue" {
  environment_name = var.eb_blue_env_name
}

data "aws_elasticbeanstalk_environment" "green" {
  environment_name = var.eb_green_env_name
}

resource "aws_route53_record" "blue_record" {
  zone_id = var.hosted_zone_id
  name    = "app." + var.domain_name # Replace "app" with your desired subdomain
  type    = "A"
  set_identifier = "blue"
  ttl     = 60
  weighted_routing_policy {
    weight = 70 # Blue environment receives 70% of traffic
  }
  records = [data.aws_elasticbeanstalk_environment.blue.endpoint]
}

resource "aws_route53_record" "green_record" {
  zone_id = var.hosted_zone_id
  name    = "app." + var.domain_name # Replace "app" with your desired subdomain
  type    = "A"
  set_identifier = "green"
  ttl     = 60
  weighted_routing_policy {
    weight = 30 # Green environment receives 30% of traffic
  }
  records = [data.aws_elasticbeanstalk_environment.green.endpoint]
}
