        log_prefix = "lex-logs"
        kms_key_arn = "arn:aws:kms:us-east-1:123456789012:key/abcdef01-2345-6789-abcd-ef0123456789" # Replace with a valid ARN
      }
    }
  }

  code_hook_settings {
    lambda_code_hook {
      lambda_arn = "arn:aws:lambda:us-east-1:123456789012:function:tripReservationLambda" # Replace with a valid ARN
      message_version = "1.0"
    }
  }
  code_hook_settings {
    lambda_code_hook {
      lambda_arn = "arn:aws:lambda:us-east-1:123456789012:function:tripCancellationLambda" # Replace with a valid ARN
      message_version = "1.0"
    }
  }

  tags = {
    Environment = "Production"
  }
}

