  name = "example"
  type = "encryption"
  policy = jsonencode({
    "Rules" = [
      {
        "Resource" = [
          "collection/example"
        ],
        "ResourceType" = "collection"
      }
    ],
    "AWSOwnedKey" = true
  })
}

resource "aws_opensearchserverless_collection" "test_collection" {
  name = "example"
  depends_on = [aws_opensearchserverless_security_policy.example]
}

resource "aws_kinesis_firehose_delivery_stream" "test_stream" {
