resource "aws_kinesis_analytics_v2_application" "example" {
  name             = "example-kinesis-analytics-app"
  runtime_environment = "JAVA11"
  service_role_arn = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:role/KinesisAnalyticsRole" # Replace with your IAM Role ARN

  application_configuration {
    application_code_configuration {
      code_location {
        bucket_name = "your-code-bucket-name" # Replace with your S3 bucket name
        object_key  = "kinesis-analytics-app.zip" # Replace with your application zip file in S3
      }
    }
    environment_properties {
      property_groups {
        property_group_name = "ApplicationProperties"
        properties = {
          "Parallelism" = "1"
        }
      }
    }
    kinesis_input {
      input_name = "input_stream"
      input_stream_type = "KINESIS"
      input_configuration {
        record_format {
          record_format_type = "JSON"
        }
        kinesis_input_configuration {
          resource_arn  = "arn:aws:kinesis:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:stream/your-kinesis-stream-name" # Replace with your Kinesis Stream ARN
          record_processing_mode = "REALTIME"
        }
      }
    }
    kinesis_output {
      output_name = "output_stream"
      output_stream_type = "KINESIS"
      output_configuration {
        kinesis_output_configuration {
          resource_arn = "arn:aws:kinesis:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:stream/your-destination-kinesis-stream-name" # Replace with your Destination Kinesis Stream ARN
          record_format_type = "JSON"
        }
      }
    }
  }

  tags = {
    Name = "Kinesis Analytics Example"
  }
}


