      kubectl --kubeconfig="${path.module}/kubeconfig" -n kube-system patch deployment coredns \n        -p '{"spec":{"template":{"spec":{"containers":[{"name":"coredns","image":"k8s.gcr.io/coredns/coredns:latest"}]}}}}'
