terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

# Public Subnet
resource "aws_subnet" "public_subnet" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

# Private Subnet
resource "aws_subnet" "private_subnet" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ

  tags = {
    Name = "private-subnet"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Route Table for Public Subnet
resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate Public Subnet with Public Route Table
resource "aws_route_table_association" "public_subnet_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_route_table.id
}

# Launch Template
resource "aws_launch_template" "example" {
  name_prefix   = "launch-template-"
  image_id      = "ami-0c55b96436051572a" # Latest Amazon Linux 2 AMI - us-east-1. Verify the latest AMI ID for your region.
  instance_type = "t2.micro"

  network_interfaces {
    associate_public_ip_address = true # Applies to the subnet, also configured in subnet
    security_groups = [] # Add security groups as needed.
  }

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "example-instance"
    }
  }
}

# EC2 Fleet
resource "aws_ec2_fleet" "example" {
  name = "example-fleet"

  launch_template_config {
    launch_template_id = aws_launch_template.example.id
    version            = "$Latest"
  }

  target_capacity_specification {
    on_demand_capacity = 5
    spot_capacity       = 4
  }

  fleet_type = "mixed"

  # Instance Types - can be specified here as an alternative to using a Launch Template
  # instance_types = ["t2.micro"]

  # Subnet IDs can be specified for where fleet would run.  If omitted, all AZs in region are used
  # subnet_ids = [aws_subnet.public_subnet.id, aws_subnet.private_subnet.id]


  tags = {
    Name = "example-fleet"
  }
}

