resource "aws_sagemaker_pipeline" "example" {
  name             = "example-pipeline"
  role_arn         = "arn:aws:iam::123456789012:role/SageMakerRole"
  tags             = {
    Name = "example-pipeline"
  }

  pipeline_definition = jsonencode({
    Steps = [
      {
        Name = "DataPreparationStep"
        Action = {
          Type = "DataPreparation"
          Parameters = {
            DataSource = {
              S3DataSource = {
                S3DataType = "S3Prefix"
                S3Uri      = "s3://your-input-bucket/data/"
                S3DataDistributionType = "FullyReplicated"
              }
            }
            TargetDataSource = {
              S3DataSource = {
                S3DataType = "S3Prefix"
                S3Uri      = "s3://your-output-bucket/prepared-data/"
                S3DataDistributionType = "FullyReplicated"
              }
            }
            DataProcessingParameters = {
              ProcessingToolSpecification = {
                ProcessingToolType = "Spark"
                ProcessingSpec = {
                  ContainerSpec = {
                    ImageUri = "arn:aws:sagemaker:us-east-1:123456789012:container/spark"
                    ImageVersion = "1.0.0"
                  }
                  EnvironmentVariables = {
                    SPARK_DRIVER_MEMORY = "4g"
                  }
                }
              }
            }
          }
        }
      },
      {
        Name = "TrainingStep"
        Action = {
          Type = "Training"
          Parameters = {
            TrainingInputMode = "File"
            TrainingJobName = "example-training-job"
            AlgorithmSpecification = {
              TrainingImage = "683805738003.dkr.ecr.us-east-1.amazonaws.com/xgboost:latest"
              TrainingInputMode = "File"
            }
            InputDataConfig = [
              {
                ChannelName = "training"
                DataSource = {
                  S3DataSource = {
                    S3DataType = "S3Prefix"
                    S3Uri      = "s3://your-output-bucket/prepared-data/"
                    S3DataDistributionType = "FullyReplicated"
                  }
                }
              }
            ]
            OutputDataConfig = {
              S3OutputPath = "s3://your-output-bucket/model-output/"
            }
            ResourceConfig = {
              InstanceCount = 1
              InstanceType  = "ml.m5.xlarge"
              VolumeSizeInGB = 30
            }
          }
        }
      }
    ]
  })
}

