# Provisioner to mount the EFS filesystem
resource "null_resource" "mount_efs_instance_1" {
  depends_on = [aws_instance.instance_1]

  connection {
    type        = "ssh"
    user        = "ec2-user"
    private_key = file("~/.ssh/id_rsa") #Replace with your private key path!
    host        = aws_instance.instance_1.public_ip # Will not work in private subnets - use a bastion host or similar.
  }

  provisioner "remote-exec" {
    inline = [
      "sudo mkdir -p /mnt/efs",
      "sudo mount -t efs ${aws_efs_file_system.default.id}:/ /mnt/efs",
      "sudo chown -R ec2-user:ec2-user /mnt/efs"
    ]
  }
}

resource "null_resource" "mount_efs_instance_2" {
