  security_group_ids            = [aws_security_group.redis_sg.id]
  automatic_failover_enabled    = true

  tags = {
    Name = "MyElastiCache"
  }
}

resource "aws_security_group" "redis_sg" {
  name        = "redis-sg"
  description = "Security group for Redis"
  vpc_id      = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    security_groups = [aws_security_group.redis_sg.id]  # Allow traffic from within the security group
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_iam_user_policy" "elasticache_access" {
  name        = "ElasticacheAccessPolicy"
  description = "Policy to allow IAM user access to ElastiCache"
  user        = "your_iam_user_name" # Replace with your IAM user name

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "elasticache:DescribeReplicationGroups",
          "elasticache:DescribeCacheClusters",
          "elasticache:DescribeReservedCacheNodes",
          "elasticache:TestReplicationGroupFailover"
        ],
        Effect   = "Allow",
        Resource = "*"
