      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  broker_node_group_info {
    client_subnets = [
      "subnet-xxxxxxxxxxxxxxxxx", # Replace with your subnet IDs
      "subnet-yyyyyyyyyyyyyyyyy", # Replace with your subnet IDs
      "subnet-zzzzzzzzzzzzzzzzz"  # Replace with your subnet IDs
    ]
    instance_type = "kafka.m5.large"
    security_groups = [
      "sg-xxxxxxxxxxxxxxxxx" # Replace with your security group ID
    ]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  configuration_info {
    arn = "arn:aws:kafka:us-east-1:123456789012:configuration/my-kafka-config" # Replace with your configuration ARN, or remove this block for default configuration
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-east-1:123456789012:key/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your KMS key ARN.  Required if using Encryption in Transit
  }

  open_to_public_ca_certificates = false # adjust as needed
  client_authentication {
    tls {
      certificate_authority_arns = []
    }
  }
  logging_info {
    broker_log_groups = [
      {
        log_group_name = "my-msk-broker-logs"
        log_type = "BROKER"
      },
      {
        log_group_name = "my-msk-controller-logs"
        log_type = "CONTROLLER"
      },
      {
        log_group_name = "my-msk-zookeeper-logs"
        log_type = "ZOOKEEPER"
      }
    ]
  }

  tags = {
    Name = "MSK Cluster"
  }
}

