    revision = 1
  }
  encryption_info {
    encryption_at_rest_kms_key_id = "alias/aws/kafka"
  }
  open_to_public_ca_certificates = false
  tags = {
    Name = "example-msk-cluster"
  }
}

resource "aws_msk_configuration" "example_config" {
  name             = "example-config"
  kafka_versions = ["2.8.1"]
  server_properties = <<EOF
auto.create.topics.enable = true
delete.topic.enable = true
default.replication.factor = 3
min.insync.replicas = 2
log.retention.hours = 168
EOF
}
resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose"
  destination = "s3"
  s3_configuration {
    role_arn                        = "arn:aws:iam::xxxxxxxxxxxx:role/KinesisFirehoseRole" # Replace with your Firehose role ARN
    bucket_name                     = "your-s3-bucket-name" # Replace with your S3 bucket name
    prefix                          = "msk-logs/"
    clock_skew_tolerance_in_seconds = 300
  }
  input_format_configuration {
    pattern {
      pattern = "application/json"
    }
  }
}

resource "aws_msk_cluster_policy" "example" {
  cluster_name = aws_msk_cluster.example.cluster_name
  policy       = jsonencode({
    "clientVpcConfig": {
      "clientAddresses": [
        "0.0.0.0/0" # Ideally restrict to your IP addresses or VPC CIDR
      ],
      "securityGroups": [
        "sg-xxxxxxxxxxxxxxxxx" # Replace with your security group ID
      ]
    }
  })
}

