provider "aws" {
  region = "us-east-1"
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  broker_node_group {
    client_subnets = [
      "subnet-xxxxxxxxxxxxxxxxx" # Replace with your subnet IDs
    ]
    security_groups = [
      "sg-xxxxxxxxxxxxxxxxx" # Replace with your security group IDs
    ]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
    instance_type = "kafka.m5.large"
  }

  configuration_info {
    arn           = "arn:aws:kafka:us-east-1:xxxxxxxxxxxx:configuration/my-msk-config" # Replace with your MSK configuration ARN
    revision      = 1
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-east-1:xxxxxxxxxxxx:key/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your KMS key ID
  }

  open_to_public_ca_certificates = false
}

resource "aws_msk_connect_custom_plugin" "debezium_plugin" {
  name        = "debezium-plugin"
  location    = "s3://your-s3-bucket/debezium.zip" # Replace with your S3 bucket and object key
}

resource "aws_msk_connect_connector" "debezium_connector" {
  name        = "debezium-connector"
  cluster_arn = aws_msk_cluster.msk_cluster.arn
  plugins = [
    {
      name = "debezium-plugin"
      path = "connectors/debezium"
    }
  ]

  capacity {
    auto_scaling {
      max_capacity = 3
      min_capacity = 1
    }
  }

  configuration = {
    "connector.class" = "io.debezium.connector.jdbc.JdbcConnector"
    # Add other Debezium connector configurations here
    "database.hostname" = "your_database_hostname" #Replace with database hostname
    "database.port" = "5432" # Replace with database port
    "database.user" = "your_database_user" # Replace with database user
    "database.password" = "your_database_password" # Replace with database password
  }
}

