terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2" # Replace with your desired region
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  broker_node_group {
    client_subnets = [
      "subnet-xxxxxxxxxxxxxxxxx", # Replace with your subnet IDs
      "subnet-yyyyyyyyyyyyyyyyy",
      "subnet-zzzzzzzzzzzzzzzzz"
    ]
    instance_type = "kafka.m5.large"
    security_groups = [
      "sg-xxxxxxxxxxxxxxxxx" # Replace with your security group ID
    ]
  }
  configuration_info {
    arn = aws_msk_configuration.msk_configuration.arn
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "alias/aws/kms" # Replace with your KMS key alias
  }

  open_monitoring {
    prometheus {
      enabled = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        group_name = "/aws/msk/broker-logs"
        log_type   = "broker"
      }
    }
    client_logs {
      cloudwatch_logs {
        group_name = "/aws/msk/client-logs"
        log_type   = "client"
      }
    }
    controller_logs {
      cloudwatch_logs {
        group_name = "/aws/msk/controller-logs"
        log_type   = "controller"
      }
    }
  }
}

# MSK Configuration
resource "aws_msk_configuration" "msk_configuration" {
  name             = "my-msk-config"
  kafka_versions = ["2.8.1"]
  server_properties = <<EOF
auto.create.topics.enable = true
delete.topic.enable = true
EOF
}

# S3 Bucket for MSK Connect Plugin
resource "aws_s3_bucket" "msk_connect_plugin_bucket" {
  bucket = "msk-connect-plugin-bucket-xxxxxxxxxxx" #Replace with a unique bucket name
  acl    = "private"
}

# MSK Connect Custom Plugin
resource "aws_msk_connect_custom_plugin" "msk_connect_custom_plugin" {
  name            = "debezium-plugin"
  location {
    s3 {
      bucket      = aws_s3_bucket.msk_connect_plugin_bucket.bucket
      object_key = "debezium.zip" # Assuming the zip is uploaded to the bucket
    }
  }
}

# Kinesis Data Firehose
resource "aws_kinesis_firehose_delivery_stream" "kinesis_firehose" {
  name        = "msk-firehose-stream"
  destination = "s3"  # Destination should be S3
  s3_configuration {
    bucket      = "msk-firehose-output-bucket-xxxxxxxxxxxx" # Replace with your S3 bucket name
    role_arn    = "arn:aws:iam::xxxxxxxxxxxx:role/kinesis-firehose-role" #replace with your firehose role ARN
    prefix = "msk-data/"
    compression_format = "GZIP"
  }
}

# MSK Connect Connector
resource "aws_msk_connect_connector" "msk_connect_connector" {
  name            = "debezium-connector"
  capacity {
    auto_scaling {
      max_capacity = 10
      min_capacity = 1
    }
  }
  connector_configuration {
    properties = {
      "tasks.max"      = "1"
      "topics"         = "my-topic"        #Replace with the name of the topic to connect to
      "connector.class" = "io.debezium.connector.jdbc.JdbcSourceConnector" 
      "database.hostname" = "your_db_hostname"  # Database hostname
      "database.port" = "5432"                  # database port
      "database.user" = "your_db_user"       # database user
      "database.password" = "your_db_password" # database password
      "database.server.name" = "your_db_server_name"
      "database.history.kafka.bootstrap.servers" = aws_msk_cluster.msk_cluster.bootstrap_brokers
      "database.history.kafka.topic" = "schema-history"
      "plugin.name" = "debezium-plugin"
    }
  }
  service_arn = aws_msk_connect_worker_configuration.msk_connect_worker_configuration.service_arn
}

resource "aws_msk_connect_worker_configuration" "msk_connect_worker_configuration" {
  name             = "my-connect-worker-config"
  current_version = "1.0"
  description      = "MSK Connect Worker Configuration"
  worker_config {
    worker_count = 2
    instance_type = "worker.m5.large"
    security_groups = [
      "sg-xxxxxxxxxxxxxxxxx" # Replace with your security group ID
    ]
  }
}

