    auto_pause               = true
    min_capacity             = 1
    max_capacity             = 2
    seconds_until_auto_pause = 300
  }

  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.aurora_sg.id]

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

resource "aws_db_subnet_group" "default" {
  name       = "aurora-mysql-subnet-group"
  subnet_ids = [
    "subnet-xxxxxxxxxxxxxxxxx", # replace with actual subnet IDs
    "subnet-yyyyyyyyyyyyyyyyy", # replace with actual subnet IDs
  ]

  tags = {
    Name = "aurora-mysql-subnet-group"
  }
}

resource "aws_security_group" "aurora_sg" {
  name        = "aurora-mysql-sg"
  description = "Allow access to Aurora MySQL"

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production!
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-mysql-sg"
  }
}

