provider "aws" {
  region = "us-west-1"
  alias  = "primary"
}

provider "aws" {
  region = "us-west-2"
  alias  = "secondary"
}

resource "aws_dynamodb_table" "example" {
  name             = "global-table-example"
  billing_mode     = "PROVISIONED"
  read_capacity    = 5
  write_capacity   = 5
  hash_key         = "id"

  global_secondary_index {
    name               = "gsi1"
    projection {
      projection_type = "ALL"
    }
    key_schema {
      attribute_name = "name"
      key_type       = "HASH"
    }
    provisioned_read_capacity = 5
    provisioned_write_capacity = 5
  }
}

resource "aws_dynamodb_global_table" "example" {
  name = "global-table-example"

  dynamodb_table {
    region_name = "us-west-1"
    table_name  = aws_dynamodb_table.example.name
  }

  dynamodb_table {
    region_name = "us-west-2"
    table_name  = aws_dynamodb_table.example.name
  }
}

