}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# VPC 1
resource "aws_vpc" "vpc1" {
  cidr_block = "10.1.0.0/16"
  tags = {
    Name = "VPC-1"
  }
}

# Subnet for VPC 1
resource "aws_subnet" "subnet1a" {
  vpc_id     = aws_vpc.vpc1.id
  cidr_block = "10.1.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "VPC-1-Subnet-A"
  }
}

# VPC 2
resource "aws_vpc" "vpc2" {
  cidr_block = "10.2.0.0/16"
  tags = {
    Name = "VPC-2"
  }
}

# Subnet for VPC 2
resource "aws_subnet" "subnet2a" {
  vpc_id     = aws_vpc.vpc2.id
  cidr_block = "10.2.1.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "VPC-2-Subnet-A"
  }
}

# VPC Peering Connection
resource "aws_vpc_peering_connection" "vpc_peering" {
  vpc_id      = aws_vpc.vpc1.id
  peer_vpc_id = aws_vpc.vpc2.id
  auto_accept = true

  tags = {
    Name = "VPC-Peering-Connection"
  }
}

# Route in VPC 1 to access VPC 2's CIDR
resource "aws_route" "route1" {
  route_table_id         = aws_vpc.vpc1.default_route_table_id
  destination_cidr_block = "10.2.0.0/16"
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peering.id
}

# Route in VPC 2 to access VPC 1's CIDR
resource "aws_route" "route2" {
  route_table_id         = aws_vpc.vpc2.default_route_table_id
  destination_cidr_block = "10.1.0.0/16"
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peering.id
}

