  acl    = "private"

  tags = {
    Name        = "Inventory Bucket"
    Environment = "Production"
  }
}


# Inventory Configuration
resource "aws_s3_bucket_inventory_configuration" "inventory" {
  bucket = aws_s3_bucket.main_bucket.id
  id    = "weekly-csv-inventory"

  destination {
    bucket = aws_s3_bucket.inventory_bucket.id
    format = "CSV"
  }

  schedule {
    frequency = "Weekly"
  }

  object_version {
    enabled = true
  }
}

