provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

# Main S3 Bucket
resource "aws_s3_bucket" "main_bucket" {
  bucket = "unique-main-bucket-name" # Replace with a unique bucket name
  acl    = "private"

  versioning {
    enabled = true
  }

  tags = {
    Name        = "Main Bucket"
    Environment = "Production"
  }
}

# Inventory Bucket
resource "aws_s3_bucket" "inventory_bucket" {
  bucket = "unique-inventory-bucket-name" # Replace with a unique bucket name
  acl    = "private"

  tags = {
    Name        = "Inventory Bucket"
    Environment = "Production"
  }
}


# Inventory Configuration
resource "aws_s3_bucket_inventory_configuration" "inventory" {
  bucket = aws_s3_bucket.main_bucket.id
  id    = "weekly-csv-inventory"

  destination {
    bucket = aws_s3_bucket.inventory_bucket.id
    format = "CSV"
  }

  schedule {
    frequency = "Weekly"
  }

  object_version {
    enabled = true
  }
}
