provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# S3 Bucket for storing grading outputs
resource "aws_s3_bucket" "grading_output_bucket" {
  bucket = "cs-course-grading-outputs-${random_id.random_id.hex}"
  acl    = "private"

  tags = {
    Name        = "CS Course Grading Outputs"
    Environment = "Development"
  }
}

resource "random_id" "random_id" {
  byte_length = 8
}

# IAM Role for CodeBuild to access S3 and GitHub
resource "aws_iam_role" "codebuild_role" {
  name               = "cs-course-codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "cs-course-codebuild-policy"
  description = "Policy for CodeBuild to access S3 and GitHub"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:s3:::cs-course-grading-outputs-${random_id.random_id.hex}/*"
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "*"
      },
      {
        Action = [
          "sts:AssumeRole"
        ],
        Effect   = "Allow",
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}



# CodeBuild Project
resource "aws_codebuild_project" "grading_project" {
  name         = "cs-course-grading-project"
  description  = "CodeBuild project for autograding student submissions"

  source {
    type      = "GITHUB"
    location  = "https://github.com/<your_github_organization>/<your_student_submission_repo>" # Replace with your GitHub repo
    buildspec = "buildspec.yml" # Assumes buildspec.yml exists in the repo
  }

  environment {
    compute {
      type  = "BUILD_GENERAL1_SMALL"
      image = "aws/codebuild/standard:7.0"
    }
    environment_variables = [
      {
        name  = "S3_BUCKET"
        value = aws_s3_bucket.grading_output_bucket.bucket
      },
      {
        name = "GITHUB_TOKEN"
        value = "YOUR_GITHUB_TOKEN" # Replace with a GitHub personal access token
      }
    ]
  }

  artifacts {
    type = "S3"
    path = "grading_results"
    bucket = aws_s3_bucket.grading_output_bucket.bucket
  }

  service_role = aws_iam_role.codebuild_role.arn
}

output "s3_bucket_name" {
  value = aws_s3_bucket.grading_output_bucket.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.grading_project.name
}

