terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

resource "aws_vpc" "autograde_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "autograde-vpc"
  }
}

resource "aws_subnet" "autograde_subnet" {
  vpc_id            = aws_vpc.autograde_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  tags = {
    Name = "autograde-subnet"
  }
}

resource "aws_internet_gateway" "autograde_igw" {
  vpc_id = aws_vpc.autograde_vpc.id
  tags = {
    Name = "autograde-igw"
  }
}

resource "aws_route_table" "autograde_route_table" {
  vpc_id = aws_vpc.autograde_vpc.id
  tags = {
    Name = "autograde-route-table"
  }
}

resource "aws_route" "autograde_route" {
  route_table_id         = aws_route_table.autograde_route_table.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.autograde_igw.id
}

resource "aws_security_group" "autograde_sg" {
  name        = "autograde-sg"
  description = "Security group for CodeBuild"
  vpc_id      = aws_vpc.autograde_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] #Restrict this to your IP
  }
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"] # No outbound internet access for submissions
  }
}

resource "aws_codebuild_project" "autograde_project" {
  name         = "autograde-project"
  description  = "CodeBuild project for autograding student submissions"

  source {
    type      = "GITHUB"
    location  = "https://github.com/<your-org>/<student-repo>" # Replace with the student repository URL
    git_clone_depth = 10
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0" #Consider a specific image with all necessary tools.
    type                        = "LINUX"
    privileged_mode              = false
    environment_variables = {
      # Define any necessary environment variables for the build process
    }
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograde-logs"
      stream_name = "autograde-stream"
    }
  }

  vpc_config {
    vpc_id             = aws_vpc.autograde_vpc.id
    subnets            = [aws_subnet.autograde_subnet.id]
    security_group_ids = [aws_security_group.autograde_sg.id]
  }
}

