  # Allow inbound SSH from your IP (for debugging - REMOVE FOR PRODUCTION)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["YOUR_IP_ADDRESS/32"] # Replace with YOUR IP
  }
  # Allow all outbound traffic (required for CodeBuild to pull images)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
