}

# S3 Bucket for storing cat images
resource "aws_s3_bucket" "cat_images_bucket" {
  bucket = "cat-images-bucket-unique-name"  # Replace with a globally unique name
  acl    = "private"

  tags = {
    Name        = "Cat Images Bucket"
    Environment = "Dev"
  }
}

# IAM Role for Lambda function
resource "aws_iam_role" "lambda_role" {
  name = "lambda_cat_api_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lambda.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      }
    ]
  })
}

resource "aws_iam_policy" "lambda_s3_policy" {
  name        = "lambda_s3_access_policy"
  description = "Policy to allow Lambda to access S3 bucket"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject"
        ],
        Effect   = "Allow",
        Resource = [
          "arn:aws:s3:::${aws_s3_bucket.cat_images_bucket.bucket}",
          "arn:aws:s3:::${aws_s3_bucket.cat_images_bucket.bucket}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "lambda_s3_attachment" {
  name       = "lambda_s3_attachment"
  role_name  = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_s3_policy.arn
}

# Lambda Function
resource "aws_lambda_function" "cat_api_lambda" {
  function_name = "cat-api-lambda"
  role          = aws_iam_role.lambda_role.arn
  handler       = "lambda_function.lambda_handler" # Replace with your actual handler
  runtime       = "python3.9"
  zip_file      = file("lambda_function.zip") # Replace with your Lambda code zip file path

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images_bucket.bucket
    }
  }
}

# API Gateway
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "Cat API"
  description = "API for uploading and retrieving cat images"
}

resource "aws_api_gateway_integration" "cat_integration" {
  rest_api_id           = aws_api_gateway_rest_api.cat_api.id
  http_method           = "POST"
  resource_id           = aws_api_gateway_resource.cat_upload_resource.id
  integration_http_method = "POST"
  type                  = "AWS_PROXY"
  uri                   = aws_lambda_function.cat_api_lambda.invoke_arn
}

resource "aws_api_gateway_integration" "cat_get_integration" {
  rest_api_id           = aws_api_gateway_rest_api.cat_api.id
  http_method           = "GET"
  resource_id           = aws_api_gateway_resource.cat_get_resource.id
  integration_http_method = "GET"
  type                  = "AWS_PROXY"
  uri                   = aws_lambda_function.cat_api_lambda.invoke_arn
}

resource "aws_api_gateway_resource" "cat_upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  path_part   = "upload"
}

resource "aws_api_gateway_resource" "cat_get_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  path_part   = "random"
}

resource "aws_api_gateway_method" "cat_upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.cat_upload_resource.id
  http_method   = "POST"
  authorization = "NONE"
  integration_http_method = "POST"
  integration_id = aws_api_gateway_integration.cat_integration.id
}

resource "aws_api_gateway_method" "cat_get_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.cat_get_resource.id
  http_method   = "GET"
  authorization = "NONE"
  integration_http_method = "GET"
  integration_id = aws_api_gateway_integration.cat_get_integration.id
}

# API Gateway Deployment
resource "aws_api_gateway_deployment" "cat_api_deployment" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "dev"
}

output "api_endpoint" {
  value = aws_api_gateway_deployment.cat_api_deployment.invoke_url
}

