  http_method         = "GET"
  integration_http_method = "GET"
  type                = "AWS_PROXY"
  uri                 = "arn:aws:lambda:us-east-1:${data.aws_caller_identity.current.account_id}:function:caas_get_lambda_function" # Replace with your Lambda ARN
}

