  }
}

provider "aws" {
  region = "us-east-1" # Default region, change as needed.  CloudFront operates globally, but a region is needed for provider configuration.
}

# S3 Bucket for Video Storage
resource "aws_s3_bucket" "video_bucket" {
  bucket = "video-streaming-bucket-${random_string.random_id.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  lifecycle_rule {
    id      = "log_lifecycle"
    enabled = true
    prefix  = "logs/"
  }

  tags = {
    Name        = "Video Streaming Bucket"
    Environment = "Production"
  }
}

resource "random_string" "random_id" {
  length  = 4
  special = false
  upper   = false
}

# Media Package (for HLS/DASH)
resource "aws_mediapackage_origin_endpoint" "origin_endpoint" {
  channel_id           = aws_mediapackage_channel.video_channel.id
  origin_id            = "S3Origin"
  path_style_mapping   = "/"
  time_domain_name     = "media.example.com"   # Replace with your domain
  url                  = "https://${aws_s3_bucket.video_bucket.bucket_domain_name}"
  s3_origin_config {
    server_side_encryption = "AES128"
  }
}

resource "aws_mediapackage_channel" "video_channel" {
  channel_id = "video-channel-${random_string.random_id.hex}"
  description = "Channel for streaming videos"
}

# CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  comment = "CloudFront distribution for video streaming"

  default_root_object = "index.html"

  aliases = ["video.example.com"] # Replace with your domain

  default_cache_behavior {
    target_origin_id = "S3Origin"

    viewer_protocol_policy = "redirect-to-https"
    allowed_methods        = ["GET", "HEAD", "OPTIONS"]
    cached_methods         = ["GET", "HEAD", "OPTIONS"]

    forwarded_values {
      query_string = false
      cookies      = { forward = "none" }
      headers      = ["Origin"]
    }
  }

  origins {
    origin_id = "S3Origin"
    domain_name = aws_s3_bucket.video_bucket.bucket_domain_name
    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path  #Use OAI to restrict S3 Access
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true # Or upload your own
  }

  price_class = "UseOnlyEdge"
  enabled     = true
  logging_config {
      bucket = aws_s3_bucket.video_bucket.bucket
      include_cookies = false
      prefix = "cloudfront/"
  }
}

# CloudFront Origin Access Identity (OAI) - Secure S3 access
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "Origin Access Identity for S3 Bucket"
}

# S3 Bucket Policy to allow CloudFront access
resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = "s3:GetObject",
        Principal = {
          AWS = aws_cloudfront_origin_access_identity.oai.cloudfront_user_id
        },
        Resource = "${aws_s3_bucket.video_bucket.arn}/*",
        Sid      = "CloudFrontOriginAccessIdentity"
      }
    ]
  })
}


# Route 53 Record
resource "aws_route53_record" "video_record" {
  name    = "video.example.com" # Replace with your domain
  type    = "A"
  zone_id = "YOUR_ROUTE53_ZONE_ID" # Replace with your Route 53 Hosted Zone ID
  ttl     = 300
  records = [aws_cloudfront_distribution.video_distribution.domain_name]
}
