provider "aws" {
  region = "us-east-1" # Or your preferred region
}

# Create an S3 bucket to store video content
resource "aws_s3_bucket" "video_bucket" {
  bucket = "video-streaming-bucket-unique-id" # Replace with a globally unique name
  acl    = "private"

  # Enable versioning to keep track of object versions
  versioning {
    enabled = true
  }

  # Enable server-side encryption
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

# Create an Origin Access Control (OAC) for CloudFront
resource "aws_cloudfront_origin_access_control" "oac" {
  name              = "video-oac"
  origin_type       = "S3"
  signing_behavior  = "always"
  signing_protocol  = "sigv4"
}

# Create a CloudFront distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  comment                 = "CloudFront distribution for video streaming"
  default_root_object     = "index.html"
  enabled                 = true
  is_http2_enabled        = true
  price_class             = "UseOnlyLowerPrices"

  origin {
    domain_name           = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id             = "S3Origin"
    s3_config {
      bucket                = aws_s3_bucket.video_bucket.bucket
      origin_access_control = aws_cloudfront_origin_access_control.oac.id
    }
  }

  default_cache_behavior {
    allowed_methods        = ["GET", "HEAD"]
    cached_methods         = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies      = false
    }
    target_origin_id = "S3Origin"
    viewer_protocol_policy = "redirect-to-https"
  }

  # Add a viewer certificate (ACM or IAM)
  viewer_certificate {
    cloudfront_default_certificate = true
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }
}


# Create a Route 53 hosted zone
resource "aws_route53_zone" "video_zone" {
  name = "video.example.com" # Replace with your domain name

  comment = "Route 53 zone for video streaming platform"
}

# Create a Route 53 record to point to the CloudFront distribution
resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.video_zone.zone_id
  name    = "www.video.example.com" # Replace if needed
  type    = "A"
  ttl     = 60
  records = [aws_cloudfront_distribution.video_distribution.domain_name]
}

#S3 Bucket Policy to allow CloudFront to access the bucket
resource "aws_s3_bucket_policy" "cloudfront_access" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "s3:GetObject"
        Principal = {
          AWS = "arn:aws:iam::cloudfront:user/CloudFront Origin Access Identity ${aws_cloudfront_origin_access_control.oac.canonical_user_id}"
        }
        Effect = "Allow"
        Resource = "${aws_s3_bucket.video_bucket.arn}/*"
      }
    ]
  })
}

