  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

resource "aws_route53_zone" "netflix_zone" {
  name = "netflix.com"
}

resource "aws_route53_record" "www_record" {
  zone_id = aws_route53_zone.netflix_zone.zone_id
  name    = "www.netflix.com"
  type    = "A"
  ttl     = "300"
  records = ["192.0.2.1"] # Replace with the actual IP address of your web server if not using alias
}

resource "aws_route53_record" "api_record" {
  zone_id = aws_route53_zone.netflix_zone.zone_id
  name    = "api.netflix.com"
  type    = "A"
  ttl     = "300"
  records = ["192.0.2.2"] # Replace with the actual IP address of your API server if not using alias
}
