  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow HTTP traffic"
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow HTTPS traffic"
  }

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow SSH traffic (restrict in production!)"
  }


  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound traffic"
  }

  tags = {
    Name = "video-streaming-sg"
  }
}

# Load Balancer Target Group
resource "aws_lb_target_group" "video_streaming_tg" {
  name     = "video-streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
  health_check {
    path = "/"
    port = "80"
    protocol = "HTTP"
    interval = 30
    timeout = 5
    healthy_threshold = 2
    unhealthy_threshold = 2
  }
}

# Load Balancer
resource "aws_lb" "video_streaming_lb" {
  name               = "video-streaming-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.video_streaming_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "video-streaming-lb"
  }
}

# Load Balancer Listener
resource "aws_lb_listener" "video_streaming_listener" {
  load_balancer_arn = aws_lb.video_streaming_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  }
}

# EC2 Instances
resource "aws_instance" "video_streaming_instance" {
  count         = 3 # Number of instances
  ami           = "ami-0c55bca456d770365" # Replace with a suitable AMI for your region
  instance_type = "t2.micro"
  subnet_id     = module.vpc.public_subnets[0] # Use a public subnet
  vpc_security_group_ids = [aws_security_group.video_streaming_sg.id]


  tags = {
    Name = "video-streaming-instance-${count.index}"
  }
}

# Attach Instances to Target Group
resource "aws_lb_target_group_attachment" "video_streaming_attachment" {
  count            = length(aws_instance.video_streaming_instance)
  target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  instance_id      = aws_instance.video_streaming_instance[count.index].id
  port             = 80
}

# Route53 Hosted Zone
resource "aws_route53_zone" "video_streaming_zone" {
  name = "example.com." # Replace with your domain name
}

# Route53 DNS Record
resource "aws_route53_record" "video_streaming_record" {
  zone_id = aws_route53_zone.video_streaming_zone.zone_id
  name    = "streaming.example.com" # Replace with your desired subdomain
  type    = "A"
  ttl     = "300"
  records = [aws_lb.video_streaming_lb.dns_name]
}

