provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# KMS Key for Encryption
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS encryption"
  key_usage               = "ENCRYPT_DECRYPT"
  policy                  = "{"version":"2012-10-17","statement":[{"Sid":"Allow access for RDS","Effect":"Allow","Principal":{"Service":"rds.amazonaws.com"},"Action":"kms:Encrypt","Action":"kms:Decrypt","Resource":"*"}]}
  tags = {
    Name = "rds-encryption-key"
  }
}

# VPC (Assumed to exist, replace with your VPC ID)
variable "vpc_id" {
  type        = string
  description = "The ID of the VPC"
  default     = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID
}

# Private Subnet IDs (Assumed to exist, replace with your subnet IDs)
variable "private_subnet_ids" {
  type        = list(string)
  description = "A list of private subnet IDs"
  default     = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy"] # Replace with your subnet IDs
}

# RDS Parameter Group
resource "aws_db_parameter_group" "default" {
  name        = "my-custom-postgres-params"
  family      = "postgres14" # Adjust engine version as needed
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "shared_buffers"
    value = "256MB"
  }
}

# RDS Instance
resource "aws_db_instance" "default" {
  allocated_storage    = 20 # GB
  engine               = "postgres"
  engine_version       = "14.9" # Choose your desired version
  instance_class       = "db.m5.large"
  name                 = "mydbinstance"
  identifier           = "mydbinstance"
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  multi_az             = true
  storage_encrypted    = true
  kms_key_id           = aws_kms_key.rds_key.arn
  db_parameter_group_name = aws_db_parameter_group.default.name
  username             = "admin"
  password             = "your_secure_password" # Replace with a strong password
  skip_final_snapshot  = true # Set to false for production
  publicly_accessible  = false
}

# DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "my-db-subnet-group"
  subnet_ids = var.private_subnet_ids
}

# Security Group
resource "aws_security_group" "rds" {
  name        = "rds-sg"
  description = "Security group for RDS instance"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    security_groups = [] # Allow access from specific security groups if needed
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

