provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# VPC for the Aurora cluster
resource "aws_vpc" "aurora_vpc" {
  cidr_block = "10.100.0.0/16"
  tags = {
    Name = "aurora-vpc"
  }
}

# Subnets for the Aurora cluster (at least two in different Availability Zones)
resource "aws_subnet" "aurora_subnet_1" {
  vpc_id     = aws_vpc.aurora_vpc.id
  cidr_block = "10.100.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  tags = {
    Name = "aurora-subnet-1"
  }
}

resource "aws_subnet" "aurora_subnet_2" {
  vpc_id     = aws_vpc.aurora_vpc.id
  cidr_block = "10.100.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  tags = {
    Name = "aurora-subnet-2"
  }
}

# Subnet Group for the Aurora cluster
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.aurora_subnet_1.id, aws_subnet.aurora_subnet_2.id]
  tags = {
    Name = "aurora-subnet-group"
  }
}

# Security Group for the Aurora cluster
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-sg"
  description = "Security group for Aurora MySQL"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict to your application's IPs in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
  tags = {
    Name = "aurora-sg"
  }
}

# IAM Role for RDS
resource "aws_iam_role" "rds_role" {
  name               = "rds-role"
  assume_role_policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "rds.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
POLICY

  tags = {
    Name = "rds-role"
  }
}

# IAM Policy for RDS to access Secrets Manager
resource "aws_iam_policy" "rds_secrets_manager_policy" {
  name        = "rds-secrets-manager-policy"
  description = "Policy allowing RDS to access Secrets Manager"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ],
        Effect   = "Allow",
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_secrets_manager_attachment" {
  role       = aws_iam_role.rds_role.name
  policy_arn = aws_iam_policy.rds_secrets_manager_policy.arn
}

# Create a secret in Secrets Manager
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-db-credentials"
  tags = {
    Name = "aurora-db-credentials"
  }
}

# Aurora MySQL Cluster
resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = aws_secretsmanager_secret.db_credentials.secret_id # Use the secret ARN
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  db_subnet_group_name    = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.aurora_sg.id]
  deletion_protection     = false
  tags = {
    Name = "aurora-mysql-cluster"
  }
}

# RDS Proxy
resource "aws_rds_proxy" "aurora_proxy" {
  proxy_identifier = "aurora-mysql-proxy"
  engine_family    = "MYSQL"
  vpc_subnet_ids   = [aws_subnet.aurora_subnet_1.id, aws_subnet.aurora_subnet_2.id]
  vpc_security_group_ids = [aws_security_group.aurora_sg.id]
  db_cluster_identifier = aws_rds_cluster.aurora_cluster.id
  auth_type            = "PASSWORD"
  master_user_name     = "admin"
  master_password       = aws_secretsmanager_secret.db_credentials.secret_id # Use secret ARN
  tags = {
    Name = "aurora-mysql-proxy"
  }
}

