resource "aws_s3_bucket" "example" {
  bucket = "my-unique-bucket-name"
  acl    = "private"

  tags = {
    Name = "MyS3Bucket"
  }
}

resource "aws_iam_role" "lightsail_s3_access" {
  name = "LightsailS3AccessRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lightsail.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ],
  })
}

resource "aws_iam_policy" "lightsail_s3_policy" {
  name        = "LightsailS3Policy"
  description = "Policy granting Lightsail access to S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          "arn:aws:s3:::${aws_s3_bucket.example.bucket}",
          "arn:aws:s3:::${aws_s3_bucket.example.bucket}/*",
        ],
      },
    ],
  })
