    rules {
      rule {
        rule_name = "glacier-rule"
        apply_server_side_encryption = false
        apply_tags               = false
        cross_region_copy         = false
        delete                    = false
        description              = "Moves objects to Glacier after 30 days and expires them after 365 days"

        transition {
          days          = 30
          storage_class = "GLACIER"
        }

        expiration {
          days = 365
        }
      }
    }
  }
}

