resource "aws_s3_bucket" "glacier_vault" {
  bucket = "my-glacier-vault-bucket" # Replace with a unique bucket name
  acl    = "private"

  versioning {
    enabled = true
  }

  lifecycle_rule {
    id      = "glacier_transition"
    enabled = true

    transition {
      days          = 30
      storage_class = "GLACIER"
    }
  }

  tags = {
    Name        = "Glacier Vault"
    Environment = "Production"
  }
}

resource "aws_s3_bucket_policy" "glacier_policy" {
  bucket = aws_s3_bucket.glacier_vault.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid    = "AllowSpecificIPAccess"
        Effect = "Allow",
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/your_user_name" # Replace with your IAM User ARN
        },
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject"
        ],
        Resource = [
          "arn:aws:s3:::my-glacier-vault-bucket/*" # Replace with your bucket name
        ]
      },
      {
       Sid    = "AllowListBucketIfObjectsExist"
        Effect = "Allow",
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/your_user_name" # Replace with your IAM User ARN
        },
        Action = "s3:ListBucket",
        Resource = "arn:aws:s3:::my-glacier-vault-bucket",
        Condition = {
          StringEquals = {
            "s3:prefix" = ""
          },
          "s3:object_count": {
            "numeric": [">=", "1"]
         }
        }
      }
    ]
  })
}

