  name        = "lb-sg"
  description = "Security group for internal load balancer"
  vpc_id      = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your actual VPC ID

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with the CIDR block for internal access
  }

