  name     = "target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your actual VPC ID
  health_check {
    path     = "/"
    protocol = "HTTP"
    interval = 30
    timeout  = 5
    healthy_threshold = 2
    unhealthy_threshold = 2
  }
}


resource "aws_lb_listener" "listener" {
  load_balancer_arn = aws_lb.internal.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

# Example instance to attach to the target group.  Replace with your actual instance configuration.
resource "aws_instance" "example" {
  ami           = "ami-xxxxxxxxxxxxxxxxx" # Replace with your desired AMI
  instance_type = "t2.micro"
  subnet_id     = "subnet-xxxxxxxxxxxxxxxxx" # Replace with your actual subnet ID
  vpc_security_group_ids = [aws_security_group.lb_sg.id]

  tags = {
    Name = "Example Instance"
  }
}

resource "aws_lb_target_group_attachment" "attachment" {
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id       = aws_instance.example.id
  port            = 80
}
