resource "aws_load_balancer" "example" {
  name               = "example-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.public_subnets[0].id, aws_subnet.public_subnets[1].id]

  enable_deletion_protection = false
}

resource "aws_target_group" "example" {
  name     = "example-target-group"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id

  health_check_settings {
    protocol = "TCP"
    path     = "/"
    interval_seconds = 30
    timeout_seconds   = 5
    healthy_threshold = 10
    unhealthy_threshold = 2
  }
}

resource "aws_lb_target_group_attachment" "example" {
  target_group_arn = aws_target_group.example.arn
  target_id       = "1.2.3.4" # Replace with actual instance IP
  port            = 80
}

resource "aws_security_group" "lb_sg" {
  name        = "lb-sg"
  description = "Allow inbound traffic for the load balancer"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public_subnets" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count + 1}.0/24"
  availability_zone = "${data.aws_availability_zones.available.names[count]}"

  tags = {
    Name = "public-subnet-${count + 1}"
  }
}

data "aws_availability_zones" "available" {}
```

