data "aws_iam_policy_document" "efs_policy" {
  statement {
    sid       = "AllowMountTargetAccess"
    effect    = "Allow"
    actions   = [
      "elasticfilesystem:DescribeMountTargets",
      "elasticfilesystem:DescribeFileSystems",
      "elasticfilesystem:MountFileSystem"
    ]
    resources = [
      aws_efs_file_system.example.arn,
      "arn:aws:elasticfilesystem:*:*:mounttarget/*"
    ]
  }

  statement {
    sid       = "AllowAccessToFileSystem"
    effect    = "Allow"
    actions   = [
      "elasticfilesystem:ClientMount",
      "elasticfilesystem:ClientWrite",
      "elasticfilesystem:ClientRootAccess",
      "elasticfilesystem:ClientMapIdentity"
    ]
    resources = [
      aws_efs_file_system.example.arn
    ]
  }
}

resource "aws_efs_access_point" "access_point" {
  file_system_id  = aws_efs_file_system.example.id
  posix_user {
    uid = 1000
    gid = 1000
    secondary_gids = []
  }

  root_directory {
    path = "/efs/root"
    creation_info {
      owner_gid = 1000
      owner_uid = 1000
      permissions = "777"
    }
  }

  tags = {
    Name = "example-access-point"
  }
}

resource "aws_efs_access_policy" "efs_access_policy" {
  file_system_id = aws_efs_file_system.example.id
  policy = data.aws_iam_policy_document.efs_policy.json
}

