extracted_code:
resource "aws_codebuild_project" "autograde" {
  name         = "autograde-project"
  description  = "CodeBuild project for autograding student submissions"

  source {
    type      = "GITHUB"
    location  = "https://github.com/${var.github_org}/${var.student_repo_name}.git" #Replace with student's repo
    git_clone_depth = 10
  }

  environment {
    compute_type                 = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"  # Choose appropriate image
    type                        = "LINUX"
    is_privileged_mode           = false

    environment_variable {
      name  = "COURSE_NAME"
      value = var.course_name
      type  = "PLAINTEXT"
    }
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs {
    group_name    = "/aws/codebuild/${var.course_name}-logs"
    stream_name   = "autograde-stream"
  }

  timeout_in_minutes = 30
  service_role_arn   = var.codebuild_service_role_arn

  build_spec {
    version = "0.2"
    phases {
      install {
        commands = [
          "apt-get update -y",
          "apt-get install -y --no-install-recommends <dependencies>", # Replace <dependencies>
        ]
      }
      pre_build {
        commands = [
          "echo 'Starting autograding for ${var.student_repo_name}'"
        ]
      }
      build {
        commands = [
          "echo 'Running grading commands...'",
          "<grading_command1>", #Replace with actual grading commands
          "<grading_command2>"
        ]
      }
      post_build {
        commands = [
          "echo 'Autograding complete.'"
        ]
      }
    }
    artifacts {
      files = [
        "grading_results/*" # Adjust based on output location
      ]
    }
  }


}

variable "github_org" {
  type = string
  description = "GitHub organization name"
}

variable "student_repo_name" {
  type = string
  description = "Name of the student's GitHub repository"
}

variable "course_name" {
  type = string
  description = "Name of the course"
}

variable "codebuild_service_role_arn" {
  type = string
  description = "ARN of the CodeBuild service role"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "artifact_bucket" {
  bucket_prefix = "artifact-bucket-"
}

resource "aws_codebuild_project" "autograder_build" {
  name         = "autograder_build"
  service_role = aws_iam_role.autograder_build_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.artifact_bucket.arn
    name     = "results.zip" # include this
  }

  environment { # arguments required, exact value not specified
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:7.0-24.10.29"
    type         = "LINUX_CONTAINER"
  }

  source {
    type            = "GITHUB"
    git_clone_depth = 1 # good to have, not required
    location        = "github.com/source-location"
  }
}

resource "aws_iam_role" "autograder_build_role" {
  assume_role_policy = data.aws_iam_policy_document.autograder_build_policy_assume.json
}

data "aws_iam_policy_document" "autograder_build_policy_assume" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
