provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# VPC for isolating the CodeBuild environment
resource "aws_vpc" "autograding_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "Autograding VPC"
  }
}

resource "aws_subnet" "autograding_subnet" {
  vpc_id     = aws_vpc.autograding_vpc.id
  cidr_block = "10.0.1.0/24"
  tags = {
    Name = "Autograding Subnet"
  }
}

resource "aws_internet_gateway" "autograding_igw" {
  vpc_id = aws_vpc.autograding_vpc.id

  tags = {
    Name = "Autograding IGW"
  }
}

resource "aws_route_table" "autograding_route_table" {
  vpc_id = aws_vpc.autograding_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.autograding_igw.id
  }

  tags = {
    Name = "Autograding Route Table"
  }
}

resource "aws_route_table_association" "autograding_assoc" {
  subnet_id      = aws_subnet.autograding_subnet.id
  route_table_id = aws_route_table.autograding_route_table.id
}

# S3 Bucket for storing student submissions and grading results
resource "aws_s3_bucket" "submissions_bucket" {
  bucket = "autograding-submissions-bucket-${random_id.random_id.hex}"
  acl    = "private"

  tags = {
    Name = "Student Submissions"
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "random_id" {
  byte_length = 8
}


# IAM Role for CodeBuild to access S3 and pull GitHub code.
resource "aws_iam_role" "codebuild_role" {
  name               = "CodeBuildAutogradingRole"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })

  tags = {
    Name = "CodeBuild Autograding Role"
  }
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "CodeBuildAutogradingPolicy"
  description = "Policy for CodeBuild to access S3 and GitHub"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          aws_s3_bucket.submissions_bucket.arn,
          "${aws_s3_bucket.submissions_bucket.arn}/*"
        ]
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Action = "codecommit:GitPull",
        Effect = "Allow",
        Resource = "*"
      }

    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}


# CodeBuild project to build and test submissions
resource "aws_codebuild_project" "autograding_project" {
  name         = "AutogradingProject"
  description  = "Builds and tests student submissions"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    type = "GITHUB"
    location = "YOUR_GITHUB_REPO" # Replace with your GitHub repository URL.
    auth { # Replace with appropriate auth configuration.
        type = "OAUTH"
    }
  }

  environment {
    compute {
      type = "LINUX_CONTAINER"
      image = "aws/codebuild/standard:7.0" # Choose an appropriate Base Image.
      memory = 512
    }
    environment_variables = [
      {
        name  = "S3_BUCKET"
        value = aws_s3_bucket.submissions_bucket.bucket
      }
    ]
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/autograding"
      stream_name = "autograding-log-stream"
    }
  }

  vpc_config {
    security_group_ids = [] #Configure security groups if needed
    subnet_ids         = [aws_subnet.autograding_subnet.id]
  }

  timeout_in_minutes = 60
}

