resource "aws_codebuild_project" "autograding_project" {
  name         = "AutogradingProject"
  description  = "Builds and tests student submissions"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    type = "GITHUB"
    location = "YOUR_GITHUB_REPO" # Replace with your GitHub repository URL.
    auth { # Replace with appropriate auth configuration.
        type = "OAUTH"
    }
  }

  environment {
    compute {
      type = "LINUX_CONTAINER"
      image = "aws/codebuild/standard:7.0" # Choose an appropriate Base Image.
      memory = 512
    }
    environment_variables = [
      {
        name  = "S3_BUCKET"
        value = aws_s3_bucket.submissions_bucket.bucket
      }
    ]
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/autograding"
      stream_name = "autograding-log-stream"
    }
  }

  vpc_config {
    security_group_ids = [] #Configure security groups if needed
    subnet_ids         = [aws_subnet.autograding_subnet.id]
  }

  timeout_in_minutes = 60
}
```

